import pandas as pd
import numpy as np
from typing import Dict, List
from src.core import WorldState, Ticker

def calculate_dynamic_signals(state: WorldState, history: Dict[str, List[Ticker]]) -> Dict[str, float]:
    signals = {'gemini_buy': 0.0, 'gemini_sell': 0.0}

    for symbol, tickers in history.items():
        if len(tickers) < 20:
            continue

        df = pd.DataFrame([t.model_dump() for t in tickers])
        closes = df['close'].values
        returns = np.diff(closes) / closes[:-1]

        # Volatility-adjusted momentum factor
        current_vol = np.std(returns[-10:])
        momentum = (closes[-1] - closes[-5]) / closes[-5]

        # Force a high-frequency trigger based on threshold-crossing or micro-mean reversion
        if momentum > (current_vol * 0.5):
            signals['gemini_buy'] = 1.0
            signals['gemini_sell'] = 0.0
        elif momentum < -(current_vol * 0.5):
            signals['gemini_buy'] = 0.0
            signals['gemini_sell'] = 1.0
        else:
            # Fallback: Capture micro-price liquidity flow direction
            if closes[-1] >= closes[-2]:
                signals['gemini_buy'] = 1.0
            else:
                signals['gemini_sell'] = 1.0

    return signals

