import pandas as pd
import numpy as np
from typing import Dict, List
from src.core import WorldState, Ticker

def calculate_dynamic_signals(state: WorldState, history: Dict[str, List[Ticker]]) -> Dict[str, float]:
    signals = {}
    gemini_buy = 0.0
    gemini_sell = 0.0

    for symbol, tickers in history.items():
        if len(tickers) < 20:
            continue

        df = pd.DataFrame([t.model_dump() for t in tickers])
        curr_price = df['close'].iloc[-1]

        # Faster EMA 5 for aggressive scalping
        ema_5 = df['close'].ewm(span=5, adjust=False).mean().iloc[-1]

        # Bollinger Band Width for volatility thresholding
        std_dev = df['close'].rolling(window=10).std().iloc[-1]
        bb_width = (df['close'].rolling(window=10).mean().iloc[-1] + (2 * std_dev)) - (df['close'].rolling(window=10).mean().iloc[-1] - (2 * std_dev))

        # RSI-style acceleration using price difference
        diff = curr_price - df['close'].shift(1).iloc[-1]

        # Mutation Logic: If high volatility, trade breakouts; otherwise, trade EMA mean reversion
        if bb_width > (curr_price * 0.0002):
            if diff > 0:
                gemini_buy = 1.0
            else:
                gemini_sell = 1.0
        else:
            # Force signal generation even in low vol based on EMA positioning
            if curr_price > ema_5:
                gemini_buy = 1.0
            else:
                gemini_sell = 1.0

    return {"gemini_buy": gemini_buy, "gemini_sell": gemini_sell}
